parameters.jsCode:
const items = $input.all();

const allCategories = [];

items.forEach(item => {
  let contentStr = item.json.content || '';

  // Normalize formatting to make parsing reliable
  contentStr = contentStr
    .replace(/\n/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  if (contentStr === '[]' || contentStr === '' || !contentStr) return;

  try {
    const parsed = JSON.parse(contentStr);

    if (Array.isArray(parsed)) {
      parsed.forEach(obj => {
        if (obj && typeof obj === 'object') {
          const code = (obj.categorycode || '').trim();
          if (code !== '') {
            allCategories.push({
              categorycode: code,
              categoryname: (obj.categoryname || '').trim()
            });
          }
        }
      });
    }
  } catch (e) {
    // skip bad entries silently
  }
});

// Return ONE item containing the plain object (no outer array)
return {
  json: {
    categories: allCategories
  }
};

